import java.util.Scanner;

public class SecureBufferHandling {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        char[] buffer = new char[10];

        // Validate input length to prevent buffer overflow
        if (userInput.length() > buffer.length) {
            System.out.println("Input string is too long. Please enter a string with maximum length " + buffer.length + ".");
            return;
        }

        // Copy input to buffer safely
        userInput.getChars(0, Math.min(userInput.length(), buffer.length), buffer, 0);

        System.out.println("Input processed successfully.");
    }
}

### Explanation:
취약유형: Buffer Overflow
